import requests
import json

def refresh_oauth2_token(token_url: str, refresh_token: str, client_id: str, client_secret: str = None, scope: str = None) -> dict:
    """
    OAuth2 토큰을 갱신하는 함수입니다.

    Args:
        token_url (str): 토큰 엔드포인트 URL.
        refresh_token (str): 갱신할 토큰.
        client_id (str): 클라이언트 ID.
        client_secret (str, optional): 클라이언트 시크릿. 기본값은 None.
        scope (str, optional): 요청할 스코프 (공백으로 구분된 문자열). 갱신 시에는 보통 기존 스코프를 유지하거나 생략합니다. 기본값은 None.

    Returns:
        dict: 갱신된 토큰 정보를 포함하는 딕셔너리 (예: {'access_token': '...', 'expires_in': ..., 'token_type': '...', 'refresh_token': '...'}).

    Raises:
        requests.exceptions.RequestException: HTTP 요청 또는 응답 처리 중 오류 발생 시.
        ValueError: 서버 응답이 유효한 JSON 형식이 아닐 경우.
    """
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded'
    }

    data = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': client_id
    }

    if client_secret:
        data['client_secret'] = client_secret
    if scope:
        data['scope'] = scope

    try:
        response = requests.post(token_url, data=data, headers=headers)
        response.raise_for_status()  # 200 이외의 HTTP 상태 코드에 대해 예외 발생

        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"Token refresh request failed: {e}")
        if e.response is not None:
            try:
                error_details = e.response.json()
                print(f"Server error details: {json.dumps(error_details, indent=2)}")
            except json.JSONDecodeError:
                print(f"Server response was not JSON: {e.response.text}")
        raise
    except json.JSONDecodeError as e:
        print(f"Failed to decode JSON response: {e}")
        print(f"Response content: {response.text}")
        raise ValueError("Server response was not valid JSON.") from e
